parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const raw = body.company || body.query || body.q || '';
const company = String(raw).trim().slice(0, 200);
if (!company || company.length < 2) {
  throw new Error('Missing or invalid "company" field. Send POST with JSON body: { "company": "SAP" }');
}
return [{ json: { company } }];

// Clearbit autocomplete: free, CORS-enabled, ~1M companies. Returns BEST pick
// + filtered candidate domains for the scraper. Filter strategy: case-insensitive
// but whitespace-preserving exact-name match (drops "Master Soft" while keeping
// "MasterSoft"). Max 2 candidates so we don't drown the prompt in noise.

const company = $('Validate Input').first().json.company;
const ERP_HINT = /erp|campus|edtech|lms|sms\b|school|college|student|academic|university/i;

let data = null, candidates = [];
try {
  const fetchCb = async (q) => {
    try {
      return await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://autocomplete.clearbit.com/v1/companies/suggest',
        qs: { query: q },
        json: true,
        timeout: 5000
      });
    } catch { return []; }
  };
  let suggestions = await fetchCb(company);
  const hasErpHit = (s) => ERP_HINT.test(s.domain || '') || ERP_HINT.test(s.name || '');
  if (Array.isArray(suggestions) && suggestions.length && !suggestions.some(hasErpHit)) {
    const erpSugs = await fetchCb(company + ' ERP');
    if (Array.isArray(erpSugs) && erpSugs.length) {
      const seen = new Set(suggestions.map(s => s.domain));
      suggestions = [...suggestions, ...erpSugs.filter(s => !seen.has(s.domain))];
    }
  }

  if (Array.isArray(suggestions) && suggestions.length) {
    const qNorm = company.toLowerCase().replace(/[^a-z0-9]/g, '');
    const score = (label) => {
      const t = (label || '').toLowerCase().replace(/[^a-z0-9]/g, '');
      if (t === qNorm) return 5;
      if (t === qNorm + 'erp' || t === qNorm + 'software' || t === qNorm + 'solutions') return 4;
      if (t.startsWith(qNorm) && t.length - qNorm.length <= 3) return 3;
      if (t.startsWith(qNorm)) return 2;
      const words = company.toLowerCase().split(/\s+/).filter(w => w.length > 2);
      if (words.length && words.every(w => t.includes(w))) return 1;
      return 0;
    };

    const ranked = suggestions
      .map(s => ({ ...s, score: score(s.name || ''), erpHint: hasErpHit(s) }))
      .filter(s => s.score > 0)
      .sort((a, b) => b.score - a.score || (b.erpHint ? 1 : 0) - (a.erpHint ? 1 : 0));

    if (ranked.length) {
      const topScore = ranked[0].score;
      const topTier = ranked.filter(s => s.score === topScore);
      const best = topTier.find(s => s.erpHint)
                || topTier.find(s => (s.domain || '').replace(/[^a-z0-9]/g, '').includes(qNorm))
                || topTier[0];
      if (best && best.domain) {
        data = {
          name: best.name,
          domain: best.domain,
          website: 'https://' + best.domain,
          logo: 'https://logo.clearbit.com/' + best.domain
        };
      }

      // Strict candidate filter: case-insensitive + whitespace-preserving equality.
      // "MasterSoft" matches "MasterSoft" but NOT "Master Soft".
      const queryLower = company.trim().toLowerCase();
      const strictMatches = ranked.filter(s => (s.name || '').trim().toLowerCase() === queryLower);
      const pool = strictMatches.length ? strictMatches : ranked.slice(0, 1);

      // Cap at 2 candidate domains. ALWAYS include the picked best domain first.
      const seen = new Set();
      candidates = [];
      if (data && data.domain) { candidates.push(data.domain); seen.add(data.domain); }
      for (const s of pool) {
        if (candidates.length >= 2) break;
        if (s.domain && !seen.has(s.domain)) {
          candidates.push(s.domain);
          seen.add(s.domain);
        }
      }
    }
  }
} catch (err) { /* swallow */ }

return [{ json: { source: 'clearbit', data, candidates } }];

// Wikidata: authoritative structured facts for companies with Wikipedia presence.
const company = $('Validate Input').first().json.company;
const COMPANY_RE = /\b(company|corporation|inc\b|ltd\b|llc\b|multinational|vendor|manufacturer|conglomerate|provider|software|enterprise|platform|system|erp)\b/i;
const norm = (s) => (s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
const labelMatches = (label, q) => {
  const t = norm(label), s = norm(q);
  if (!t || !s) return false;
  if (t === s || t.startsWith(s) || s.startsWith(t)) return true;
  const words = q.toLowerCase().split(/\s+/).filter(w => w.length > 2);
  return words.length > 0 && words.every(w => t.includes(w));
};
const trimDesc = (text, max = 400) => {
  if (!text || text.length <= max) return text || null;
  const cut = text.lastIndexOf('. ', max);
  return cut > 60 ? text.slice(0, cut + 1) : text.slice(0, max - 1) + '\u2026';
};

let data = null;
try {
  const search = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.wikidata.org/w/api.php',
    qs: {
      action: 'wbsearchentities',
      search: company,
      type: 'item',
      language: 'en',
      limit: '10',
      format: 'json'
    },
    json: true,
    timeout: 8000
  }).catch(() => null);

  const hit = (search && Array.isArray(search.search) ? search.search : []).find(r =>
    labelMatches(r.label || '', company) && COMPANY_RE.test(r.description || '')
  );

  if (hit) {
    const entityRes = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.wikidata.org/w/api.php',
      qs: {
        action: 'wbgetentities',
        ids: hit.id,
        props: 'labels|descriptions|claims|sitelinks',
        sitefilter: 'enwiki',
        languages: 'en',
        format: 'json'
      },
      json: true,
      timeout: 8000
    }).catch(() => null);

    const entity = entityRes && entityRes.entities && entityRes.entities[hit.id];
    if (entity) {
      const claimVal = (prop) => {
        const c = entity.claims && entity.claims[prop];
        const snak = c && c[0] && c[0].mainsnak;
        if (!snak || snak.snaktype !== 'value') return null;
        const dv = snak.datavalue || {};
        const t = dv.type, v = dv.value;
        if (t === 'string')   return v;
        if (t === 'time')     return v && v.time ? v.time.slice(1, 5) : null;
        if (t === 'quantity') return v && v.amount ? String(v.amount).replace(/^\+/, '') : null;
        return null;
      };
      const website   = claimVal('P856');
      const founded   = claimVal('P571');
      const employees = claimVal('P1128');
      const hqId       = (entity.claims && entity.claims.P159 && entity.claims.P159[0] && entity.claims.P159[0].mainsnak && entity.claims.P159[0].mainsnak.datavalue && entity.claims.P159[0].mainsnak.datavalue.value && entity.claims.P159[0].mainsnak.datavalue.value.id) || null;
      const industryId = (entity.claims && entity.claims.P452 && entity.claims.P452[0] && entity.claims.P452[0].mainsnak && entity.claims.P452[0].mainsnak.datavalue && entity.claims.P452[0].mainsnak.datavalue.value && entity.claims.P452[0].mainsnak.datavalue.value.id) || null;

      let domain = null;
      try { if (website) domain = new URL(website).hostname.replace(/^www\./, ''); } catch {}

      const wikiTitle = (entity.sitelinks && entity.sitelinks.enwiki && entity.sitelinks.enwiki.title) || null;
      const idsToResolve = [hqId, industryId].filter(Boolean);

      const [wiki, labelRes] = await Promise.all([
        wikiTitle ? this.helpers.httpRequest({
          method: 'GET',
          url: 'https://en.wikipedia.org/api/rest_v1/page/summary/' + encodeURIComponent(wikiTitle),
          json: true,
          timeout: 8000
        }).catch(() => null) : Promise.resolve(null),
        idsToResolve.length ? this.helpers.httpRequest({
          method: 'GET',
          url: 'https://www.wikidata.org/w/api.php',
          qs: {
            action: 'wbgetentities',
            ids: idsToResolve.join('|'),
            props: 'labels',
            languages: 'en',
            format: 'json'
          },
          json: true,
          timeout: 8000
        }).catch(() => null) : Promise.resolve(null)
      ]);

      const hq       = hqId       ? ((labelRes && labelRes.entities && labelRes.entities[hqId] && labelRes.entities[hqId].labels && labelRes.entities[hqId].labels.en && labelRes.entities[hqId].labels.en.value) || null) : null;
      const industry = industryId ? ((labelRes && labelRes.entities && labelRes.entities[industryId] && labelRes.entities[industryId].labels && labelRes.entities[industryId].labels.en && labelRes.entities[industryId].labels.en.value) || null) : (hit.description || null);

      data = {
        name: (entity.labels && entity.labels.en && entity.labels.en.value) || hit.label,
        desc: trimDesc((wiki && wiki.extract) || null),
        website,
        domain,
        founded,
        hq,
        employees,
        industry
      };
    }
  }
} catch (err) { /* swallow — return null */ }

return [{ json: { source: 'wikidata', data } }];

// Consolidate prior lookups into one item that the Gemini chain consumes.
const company = $('Validate Input').first().json.company;
const cb = ($('Clearbit Lookup').first() && $('Clearbit Lookup').first().json && $('Clearbit Lookup').first().json.data) || null;
const wd = ($('Wikidata Lookup').first() && $('Wikidata Lookup').first().json && $('Wikidata Lookup').first().json.data) || null;
const sc = ($('Scrape Homepage').first() && $('Scrape Homepage').first().json) || null;

return [{
  json: {
    company,
    knownName:      (wd && wd.name) || (cb && cb.name) || null,
    knownDomain:    (cb && cb.domain) || (wd && wd.domain) || null,
    knownDesc:      (wd && wd.desc) || null,
    knownHq:        (wd && wd.hq) || null,
    knownFounded:   (wd && wd.founded) || null,
    knownEmployees: (wd && wd.employees) || null,
    knownIndustry:  (wd && wd.industry) || null,
    knownWebsite:   (wd && wd.website) || (cb && cb.website) || null,
    homepageText:   (sc && sc.homepageText) || null
  }
}];

parameters.text:
=Research this company: {{ $json.company }}

VERIFIED STRUCTURED FACTS (from Wikidata/Clearbit):
- Canonical name: {{ $json.knownName || 'unknown' }}
- Domain: {{ $json.knownDomain || 'unknown' }}
- Wikidata description: {{ $json.knownDesc || 'unknown' }}
- HQ: {{ $json.knownHq || 'unknown' }}
- Founded: {{ $json.knownFounded || 'unknown' }}
- Employees: {{ $json.knownEmployees || 'unknown' }}
- Industry: {{ $json.knownIndustry || 'unknown' }}

COMPANY'S OWN WEBSITE CONTENT (HIGHEST AUTHORITY when present):
{{ $json.homepageText || '(homepage was not reachable)' }}

---

Per-field instructions:

- **hq**: Look on the website for an explicit address (street + city + country), [FOOTER] address blocks, /contact pages, or phrases like "Headquartered in", "Based in", "Our office in". Format as "City, Country". If the website has it, USE IT — even if your training data says something different. If website is silent, use the verified Wikidata HQ. If both silent, use your training-data knowledge if high-confidence. Only return null when truly unknown across all three. **Ignore HQ-like cities mentioned in customer testimonials or speaker bios.**

- **founded**: 4-digit year. Use website if stated, else verified facts, else your training data (high-confidence for well-known companies).

- **employees**: numeric string ("23000") or short range ("3000-4000"). Same priority: website > verified > training data.

- **revenue**: Specific reported figure with fiscal year (e.g. "$32.7 billion (FY2024)"). Use training data confidently for major public companies if you know the most recent figure. Null only if unsure.

- **desc**: 2-3 factual sentences derived from website wording (cleaned of marketing fluff). Else from training data.

- **industry**: 1-3 word industry label.

- **erp**: SPECIFIC product name if the company sells/produces an ERP product (e.g. "MasterSoft EduERP", "Ellucian Banner", "SAP S/4HANA", "Oracle NetSuite"). Return null if the company is not an ERP vendor — don't return generic "ERP".

- **tags**: 2-4 short labels (industry segment, deployment model, public ticker if listed).

Be confident, not over-cautious. For widely-known companies, your training data IS reliable for founded/employees/revenue — don't drop those to null. Return null only when you genuinely don't know.

Return the JSON object now.

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "name":      { "type": ["string", "null"], "description": "Canonical company name" },
    "desc":      { "type": ["string", "null"], "description": "2-3 factual sentences, no marketing language" },
    "industry":  { "type": ["string", "null"], "description": "Primary industry classification" },
    "hq":        { "type": ["string", "null"], "description": "Headquarters as 'City, Country'" },
    "employees": { "type": ["string", "null"], "description": "Numeric string e.g. '23000'" },
    "founded":   { "type": ["string", "null"], "description": "4-digit founding year" },
    "revenue":   { "type": ["string", "null"], "description": "e.g. '$32.7 billion (FY2024)'" },
    "erp":       { "type": ["string", "null"], "description": "Specific ERP product name if applicable" },
    "tags":      { "type": ["array", "null"], "items": { "type": "string" }, "description": "2-4 short classification labels" }
  },
  "required": ["name", "desc", "industry", "hq", "employees", "founded", "revenue", "erp", "tags"],
  "additionalProperties": false
}

parameters.jsCode:
// Field-level priority merge.
// Priority per field: Wikidata (authoritative) > Clearbit > Gemini > pattern-inference.
// Logo always Clearbit (most reliable). Revenue/erp/tags only Gemini (others don't provide).

const cb = ($('Clearbit Lookup').first() && $('Clearbit Lookup').first().json && $('Clearbit Lookup').first().json.data) || null;
const wd = ($('Wikidata Lookup').first() && $('Wikidata Lookup').first().json && $('Wikidata Lookup').first().json.data) || null;

let gem = null;
try {
  const raw = $input.first().json;
  // Basic LLM Chain with structured parser usually outputs the parsed object directly,
  // but the wrapper key varies (output / text). Handle both.
  let out = (raw && raw.output !== undefined) ? raw.output : raw;
  if (typeof out === 'string') out = JSON.parse(out);
  gem = (out && typeof out === 'object') ? out : null;
} catch { gem = null; }

const pick = (...vals) => {
  for (const v of vals) {
    if (v !== null && v !== undefined && v !== '') return v;
  }
  return null;
};

// Pattern-inference fallback for ERP type when Gemini returns null.
const inferErp = (name, desc) => {
  const text = ((name || '') + ' ' + (desc || '')).toLowerCase();
  if (/educational?\s*erp|campus\s*(erp|management|solution)|student\s*(information|management)\s*system|school\s*(erp|management)|university\s*erp|college\s*erp/i.test(text)) return 'Educational ERP';
  if (/\berp\b|enterprise\s*resource\s*plan/i.test(text)) return 'ERP';
  return null;
};

const name = pick(wd && wd.name, cb && cb.name, gem && gem.name);
const desc = pick(wd && wd.desc, gem && gem.desc);

const merged = {
  name,
  desc,
  industry:     pick(wd && wd.industry, gem && gem.industry),
  hq:           pick(wd && wd.hq, gem && gem.hq),
  employees:    pick(wd && wd.employees, gem && gem.employees),
  founded:      pick(wd && wd.founded, gem && gem.founded),
  revenue:      pick(gem && gem.revenue),
  erp:          pick(gem && gem.erp, inferErp(name, desc)),
  tags:         (gem && Array.isArray(gem.tags) && gem.tags.length) ? gem.tags.slice(0, 4) : null,
  website:      pick(wd && wd.website, cb && cb.website),
  domain:       pick(cb && cb.domain, wd && wd.domain),
  logo:         pick(cb && cb.logo),
  logoFallback: null,
  sources: {
    clearbit: cb !== null,
    wikidata: wd !== null,
    gemini:   gem !== null
  }
};

return [{ json: merged }];

// Scrape company website with bias toward contact/about pages where HQ
// addresses live. Tail-extract footer of homepages too — addresses there often
// don't survive a generic head-clip.

const cb = $('Clearbit Lookup').first() && $('Clearbit Lookup').first().json;
const wd = ($('Wikidata Lookup').first() && $('Wikidata Lookup').first().json && $('Wikidata Lookup').first().json.data) || null;

const cbCandidates = (cb && Array.isArray(cb.candidates)) ? cb.candidates : [];
const wdDomain     = (wd && wd.domain) || null;
const cbDomain     = (cb && cb.data && cb.data.domain) || null;

const domains = [...new Set([cbDomain, ...cbCandidates, wdDomain].filter(Boolean))].slice(0, 2);

const fetchPage = async (url) => {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; CompanySnapshotBot/1.0; +https://example.com/bot)' },
      timeout: 8000,
      followRedirect: true
    });
    return typeof r === 'string' ? r : (r && r.body) ? r.body : '';
  } catch { return ''; }
};

const stripHtml = (html) => {
  if (!html || typeof html !== 'string') return '';
  return html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[^>]*>[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#0?39;/g, "'").replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
};

// Pull plausible address-bearing chunks: footer (common <footer>, last <div class="footer">),
// or last 2000 chars of body text as fallback.
const extractFooter = (html) => {
  if (!html) return '';
  const m = html.match(/<footer[\s\S]*?<\/footer>/gi);
  if (m && m.length) return stripHtml(m.join(' '));
  // Heuristic: text near "address", "headquarter", "contact us"
  return '';
};

// Each path gets its own budget so /contact (small but high-signal) isn't crowded out.
const PATH_BUDGETS = [
  { path: '/contact-us',  budget: 3000 },
  { path: '/contact',     budget: 3000 },
  { path: '/about-us',    budget: 3000 },
  { path: '/about',       budget: 3000 },
  { path: '/locations',   budget: 1500 },
  { path: '/our-offices', budget: 1500 },
  { path: '/',            budget: 3000 },
];
const PER_DOMAIN_CAP = 9000;

const sections = [];
for (const domain of domains) {
  const pieces = [];
  let used = 0;
  for (const { path, budget } of PATH_BUDGETS) {
    if (used >= PER_DOMAIN_CAP) break;
    const html = await fetchPage('https://' + domain + path);
    if (!html) continue;

    // Always include the footer (where addresses live) regardless of head budget
    const footer = extractFooter(html).slice(0, 1200);
    const head   = stripHtml(html).slice(0, Math.max(0, budget - footer.length));
    const combined = (head + (footer ? ' [FOOTER] ' + footer : '')).trim();
    if (combined.length > 80) {
      pieces.push(`[${path}] ${combined}`);
      used += combined.length;
    }
  }
  if (pieces.length) sections.push('--- ' + domain + ' ---\n' + pieces.join('\n').slice(0, PER_DOMAIN_CAP));
}

const homepageText = sections.length ? sections.join('\n\n').slice(0, 14000) : null;

return [{ json: { domains, homepageText } }];
